// Generated by OrchestKit Claude Plugin
// Created: 2026-03-14

/**
 * PostCompact Recovery — Re-injects critical context after compaction
 * CC 2.1.76+: Fires after compaction completes.
 *
 * Reads the snapshot saved by pre-compact-saver.ts and injects:
 * - Active branch and recently edited files
 * - In-progress task subjects
 * - Recent decisions
 * - Compaction frequency analytics
 *
 * Version: 1.0.0
 */

import { existsSync, readFileSync } from 'node:fs';
import { join } from 'node:path';
import type { HookInput, HookResult } from '../types.js';
import { outputWithContext, logHook, getLogDir, getSessionId } from '../lib/common.js';

interface PreservedContext {
  branch?: string;
  activeFiles?: string[];
  sessionNotes?: string;
  activeTasks?: string[];
  decisionLog?: string[];
  memoryTierSnapshot?: {
    graphEntries?: number;
    localEntries?: number;
  };
  tokenBudget?: {
    estimatedUsed?: number;
    estimatedRemaining?: number;
    effortLevel?: string;
  };
}

interface SessionState {
  lastCompaction?: string;
  compactionCount?: number;
  avgCompactionIntervalMs?: number;
  preservedContext?: PreservedContext;
  compactionHistory?: Array<{
    timestamp: string;
    contextSizeEstimate?: number;
  }>;
}

function getSessionStateFile(): string {
  const logDir = getLogDir();
  return join(logDir, 'sessions', `${getSessionId()}-state.json`);
}

function loadSessionState(stateFile: string): SessionState | null {
  try {
    if (existsSync(stateFile)) {
      return JSON.parse(readFileSync(stateFile, 'utf8'));
    }
  } catch {
    // Ignore parse errors
  }
  return null;
}

function formatInterval(ms: number): string {
  if (ms < 60_000) return `${Math.round(ms / 1000)}s`;
  return `${Math.round(ms / 60_000)}m`;
}

export function postCompactRecovery(input: HookInput): HookResult {
  const stateFile = getSessionStateFile();
  const state = loadSessionState(stateFile);

  if (!state?.preservedContext) {
    logHook('post-compact-recovery', 'No preserved context found — skipping recovery');
    return { continue: true, suppressOutput: true };
  }

  const ctx = state.preservedContext;
  const parts: string[] = [];

  // Prefer CC-provided fields (2.1.76) over file-based state for compaction metadata
  const compactionNum = input.compaction_count ?? state.compactionCount ?? '?';
  const contextAfter = input.context_size_after;

  parts.push(`[POST-COMPACTION RECOVERY] Compaction #${compactionNum} completed.`);

  if (contextAfter) {
    parts.push(`Context size after compaction: ~${Math.round(contextAfter / 1000)}k tokens`);
  }

  // Branch context
  if (ctx.branch) {
    parts.push(`Branch: ${ctx.branch}`);
  }

  // Active files
  if (ctx.activeFiles?.length) {
    const fileList = ctx.activeFiles.slice(0, 10).join(', ');
    parts.push(`Recently edited files: ${fileList}`);
  }

  // In-progress tasks
  if (ctx.activeTasks?.length) {
    parts.push(`Recent tasks: ${ctx.activeTasks.join(' | ')}`);
  }

  // Decisions
  if (ctx.decisionLog?.length) {
    const recent = ctx.decisionLog.slice(-5);
    parts.push(`Recent decisions: ${recent.join(' | ')}`);
  }

  // Compaction analytics
  if (state.avgCompactionIntervalMs && state.avgCompactionIntervalMs > 0) {
    parts.push(`Avg compaction interval: ${formatInterval(state.avgCompactionIntervalMs)}`);
  }

  // Circuit breaker awareness (CC 2.1.76: stops after 3 consecutive failures)
  const count = typeof compactionNum === 'number' ? compactionNum : (state.compactionCount || 0);
  if (count >= 3) {
    parts.push(`Warning: ${count} compactions this session — consider wrapping up or splitting work.`);
  }

  // Memory snapshot
  if (ctx.memoryTierSnapshot?.localEntries) {
    parts.push(`Memory entries at compaction: ${ctx.memoryTierSnapshot.localEntries}`);
  }

  // Token budget carry-forward (CC 2.1.89 Candlekeep insight)
  if (ctx.tokenBudget?.estimatedRemaining) {
    parts.push(`Token budget before compaction: ~${Math.round(ctx.tokenBudget.estimatedUsed || 0)}k used, ~${Math.round(ctx.tokenBudget.estimatedRemaining)}k remaining (effort: ${ctx.tokenBudget.effortLevel || 'default'})`);
  }

  const context = parts.join('\n');

  logHook('post-compact-recovery',
    `Recovered context after compaction #${state.compactionCount} ` +
    `(${ctx.activeFiles?.length || 0} files, ${ctx.activeTasks?.length || 0} tasks, ` +
    `${ctx.decisionLog?.length || 0} decisions)`
  );

  return outputWithContext(context);
}
